import{_ as o,o as t,c as i,ag as l}from"./chunks/framework.CTpQozEL.js";const h=JSON.parse('{"title":"Async exec 중복 completion 조사","description":"중복 async exec completion 주입에 대한 조사 노트","frontmatter":{"title":"Async exec 중복 completion 조사","description":"중복 async exec completion 주입에 대한 조사 노트"},"headers":[],"relativePath":"refactor/async-exec-duplicate-completion-investigation.md","filePath":"refactor/async-exec-duplicate-completion-investigation.md","lastUpdated":null}'),a={name:"refactor/async-exec-duplicate-completion-investigation.md"};function n(c,e,d,s,r,u){return t(),i("div",null,[...e[0]||(e[0]=[l('<h2 id="범위" tabindex="-1">범위 <a class="header-anchor" href="#범위" aria-label="Permalink to &quot;범위&quot;">​</a></h2><ul><li>세션: <code>agent:main:telegram:group:-1003774691294:topic:1</code></li><li>증상: 세션/실행(run) <code>keen-nexus</code>에 대한 동일한 async exec completion이 LCM에 사용자 턴(user turn)으로 두 번 기록되었습니다.</li><li>목표: 이것이 중복 세션 주입(duplicate session injection)일 가능성이 높은지, 아니면 단순 아웃바운드(outbound) 전송 재시도인지 식별하는 것입니다.</li></ul><h2 id="결론" tabindex="-1">결론 <a class="header-anchor" href="#결론" aria-label="Permalink to &quot;결론&quot;">​</a></h2><p>가장 가능성이 높은 원인은 순수한 아웃바운드 전송 재시도가 아니라 <strong>중복 세션 주입(duplicate session injection)</strong> 입니다.</p><p>게이트웨이(gateway) 측에서 가장 취약한 지점은 <strong>노드 exec completion 경로</strong> 입니다:</p><ol><li>노드 측 exec 종료 시 전체 <code>runId</code>와 함께 <code>exec.finished</code>가 emit됩니다.</li><li>게이트웨이의 <code>server-node-events</code>는 이를 system event로 변환하고 heartbeat를 요청합니다.</li><li>Heartbeat 실행은 drain된 system event 블록을 에이전트 프롬프트에 주입합니다.</li><li>임베디드 러너(embedded runner)는 해당 프롬프트를 세션 트랜스크립트(transcript)에 새 사용자 턴으로 영속화합니다.</li></ol><p>어떤 이유(replay, 재연결 중복, 업스트림 재전송, 프로듀서 중복)로든 동일한 <code>runId</code>에 대해 <code>exec.finished</code>가 게이트웨이에 두 번 도달하면, 현재 OpenClaw는 이 경로에서 <strong><code>runId</code>/<code>contextKey</code>로 키잉된 idempotency 검사가 없습니다</strong>. 두 번째 복사본은 동일한 내용을 가진 두 번째 사용자 메시지가 됩니다.</p><h2 id="정확한-코드-경로" tabindex="-1">정확한 코드 경로 <a class="header-anchor" href="#정확한-코드-경로" aria-label="Permalink to &quot;정확한 코드 경로&quot;">​</a></h2><h3 id="_1-프로듀서-노드-exec-completion-이벤트" tabindex="-1">1. 프로듀서: 노드 exec completion 이벤트 <a class="header-anchor" href="#_1-프로듀서-노드-exec-completion-이벤트" aria-label="Permalink to &quot;1. 프로듀서: 노드 exec completion 이벤트&quot;">​</a></h3><ul><li><code>src/node-host/invoke.ts:340-360</code><ul><li><code>sendExecFinishedEvent(...)</code>는 <code>exec.finished</code> 이벤트로 <code>node.event</code>를 emit합니다.</li><li>페이로드에는 <code>sessionKey</code>와 전체 <code>runId</code>가 포함됩니다.</li></ul></li></ul><h3 id="_2-게이트웨이-이벤트-수집-ingestion" tabindex="-1">2. 게이트웨이 이벤트 수집(ingestion) <a class="header-anchor" href="#_2-게이트웨이-이벤트-수집-ingestion" aria-label="Permalink to &quot;2. 게이트웨이 이벤트 수집(ingestion)&quot;">​</a></h3><ul><li><code>src/gateway/server-node-events.ts:574-640</code><ul><li><code>exec.finished</code>를 처리합니다.</li><li>텍스트를 구성합니다: <ul><li><code>Exec finished (node=..., id=&lt;runId&gt;, code ...)</code></li></ul></li><li>다음을 통해 enqueue합니다: <ul><li><code>enqueueSystemEvent(text, { sessionKey, contextKey: runId ? \\</code>exec:${runId}` : &quot;exec&quot;, trusted: false })`</li></ul></li><li>즉시 wake를 요청합니다: <ul><li><code>requestHeartbeatNow(scopedHeartbeatWakeOptions(sessionKey, { reason: &quot;exec-event&quot; }))</code></li></ul></li></ul></li></ul><h3 id="_3-system-event-중복-제거의-취약성" tabindex="-1">3. System event 중복 제거의 취약성 <a class="header-anchor" href="#_3-system-event-중복-제거의-취약성" aria-label="Permalink to &quot;3. System event 중복 제거의 취약성&quot;">​</a></h3><ul><li><code>src/infra/system-events.ts:90-115</code><ul><li><code>enqueueSystemEvent(...)</code>는 <strong>연속된 중복 텍스트</strong>만 억제합니다: <ul><li><code>if (entry.lastText === cleaned) return false</code></li></ul></li><li><code>contextKey</code>를 저장하긴 하지만, idempotency를 위해 <code>contextKey</code>를 <strong>사용하지 않습니다</strong>.</li><li>Drain 이후에는 중복 억제가 리셋됩니다.</li></ul></li></ul><p>이는 코드가 이미 안정적인 idempotency 후보(<code>exec:&lt;runId&gt;</code>)를 가지고 있음에도 불구하고, 동일한 <code>runId</code>로 재전송된 <code>exec.finished</code>가 나중에 다시 수용될 수 있음을 의미합니다.</p><h3 id="_4-wake-처리는-주요-중복-원인이-아님" tabindex="-1">4. Wake 처리는 주요 중복 원인이 아님 <a class="header-anchor" href="#_4-wake-처리는-주요-중복-원인이-아님" aria-label="Permalink to &quot;4. Wake 처리는 주요 중복 원인이 아님&quot;">​</a></h3><ul><li><code>src/infra/heartbeat-wake.ts:79-117</code><ul><li>Wake는 <code>(agentId, sessionKey)</code>로 coalesce됩니다.</li><li>동일한 대상에 대한 중복 wake 요청은 하나의 pending wake 엔트리로 축소됩니다.</li></ul></li></ul><p>따라서 <strong>중복 wake 처리만으로는</strong> 중복 이벤트 수집보다 설명력이 약합니다.</p><h3 id="_5-heartbeat가-이벤트를-소비하여-프롬프트-입력으로-변환" tabindex="-1">5. Heartbeat가 이벤트를 소비하여 프롬프트 입력으로 변환 <a class="header-anchor" href="#_5-heartbeat가-이벤트를-소비하여-프롬프트-입력으로-변환" aria-label="Permalink to &quot;5. Heartbeat가 이벤트를 소비하여 프롬프트 입력으로 변환&quot;">​</a></h3><ul><li><code>src/infra/heartbeat-runner.ts:535-574</code><ul><li>Preflight가 pending system event를 미리 살펴보고 exec-event 실행을 분류합니다.</li></ul></li><li><code>src/auto-reply/reply/session-system-events.ts:86-90</code><ul><li><code>drainFormattedSystemEvents(...)</code>가 해당 세션의 큐를 drain합니다.</li></ul></li><li><code>src/auto-reply/reply/get-reply-run.ts:400-427</code><ul><li>Drain된 system event 블록이 에이전트 프롬프트 본문 앞에 prepend됩니다.</li></ul></li></ul><h3 id="_6-트랜스크립트-주입-지점" tabindex="-1">6. 트랜스크립트 주입 지점 <a class="header-anchor" href="#_6-트랜스크립트-주입-지점" aria-label="Permalink to &quot;6. 트랜스크립트 주입 지점&quot;">​</a></h3><ul><li><code>src/agents/pi-embedded-runner/run/attempt.ts:2000-2017</code><ul><li><code>activeSession.prompt(effectivePrompt)</code>는 임베디드 PI 세션에 전체 프롬프트를 제출합니다.</li><li>이 지점이 completion에서 파생된 프롬프트가 영속화된 사용자 턴이 되는 지점입니다.</li></ul></li></ul><p>따라서 동일한 system event가 프롬프트로 두 번 재구성되면 LCM 사용자 메시지 중복이 발생하는 것은 당연한 결과입니다.</p><h2 id="순수한-아웃바운드-전송-재시도-가능성이-낮은-이유" tabindex="-1">순수한 아웃바운드 전송 재시도 가능성이 낮은 이유 <a class="header-anchor" href="#순수한-아웃바운드-전송-재시도-가능성이-낮은-이유" aria-label="Permalink to &quot;순수한 아웃바운드 전송 재시도 가능성이 낮은 이유&quot;">​</a></h2><p>Heartbeat 러너에는 실제 아웃바운드 실패 경로가 존재합니다:</p><ul><li><code>src/infra/heartbeat-runner.ts:1194-1242</code><ul><li>답변(reply)이 먼저 생성됩니다.</li><li>아웃바운드 전송은 이후 <code>deliverOutboundPayloads(...)</code>를 통해 이루어집니다.</li><li>여기서 실패하면 <code>{ status: &quot;failed&quot; }</code>를 반환합니다.</li></ul></li></ul><p>그러나 동일한 system event 큐 엔트리의 경우 이것만으로는 중복 사용자 턴을 설명하기에 <strong>충분하지 않습니다</strong>:</p><ul><li><code>src/auto-reply/reply/session-system-events.ts:86-90</code><ul><li>System event 큐는 아웃바운드 전송 이전에 이미 drain됩니다.</li></ul></li></ul><p>따라서 채널 전송 재시도만으로는 동일한 큐 이벤트가 재생성되지 않습니다. 외부 전송 누락/실패는 설명할 수 있지만, 그 자체만으로 두 번째 동일한 세션 사용자 메시지를 설명할 수는 없습니다.</p><h2 id="두-번째-신뢰도가-낮은-가능성" tabindex="-1">두 번째, 신뢰도가 낮은 가능성 <a class="header-anchor" href="#두-번째-신뢰도가-낮은-가능성" aria-label="Permalink to &quot;두 번째, 신뢰도가 낮은 가능성&quot;">​</a></h2><p>에이전트 러너에는 전체 실행 재시도 루프가 있습니다:</p><ul><li><code>src/auto-reply/reply/agent-runner-execution.ts:741-1473</code><ul><li>특정 일시적 실패의 경우 전체 실행을 재시도하고 동일한 <code>commandBody</code>를 재제출할 수 있습니다.</li></ul></li></ul><p>이는 재시도 조건이 트리거되기 전에 프롬프트가 이미 append된 상태였다면 <strong>동일한 reply 실행 내에서</strong> 영속화된 사용자 프롬프트를 중복시킬 수 있습니다.</p><p>다음과 같은 이유로 이 가능성은 중복 <code>exec.finished</code> 수집보다 낮다고 판단합니다:</p><ul><li>관측된 간격이 약 51초였는데, 이는 in-process 재시도보다는 두 번째 wake/턴에 가까워 보입니다.</li><li>보고된 반복적인 메시지 전송 실패는 즉각적인 모델/런타임 재시도보다는 별도의 이후 턴을 가리킵니다.</li></ul><h2 id="근본-원인-가설" tabindex="-1">근본 원인 가설 <a class="header-anchor" href="#근본-원인-가설" aria-label="Permalink to &quot;근본 원인 가설&quot;">​</a></h2><p>가장 신뢰도가 높은 가설:</p><ul><li><code>keen-nexus</code> completion이 <strong>노드 exec 이벤트 경로</strong>를 통해 들어왔습니다.</li><li>동일한 <code>exec.finished</code>가 <code>server-node-events</code>로 두 번 전달되었습니다.</li><li><code>enqueueSystemEvent(...)</code>가 <code>contextKey</code> / <code>runId</code>로 중복 제거하지 않기 때문에 게이트웨이가 둘 다 수용했습니다.</li><li>수용된 각 이벤트는 heartbeat를 트리거하고 PI 트랜스크립트에 사용자 턴으로 주입되었습니다.</li></ul><h2 id="제안하는-최소-외과적-수정" tabindex="-1">제안하는 최소 외과적 수정 <a class="header-anchor" href="#제안하는-최소-외과적-수정" aria-label="Permalink to &quot;제안하는 최소 외과적 수정&quot;">​</a></h2><p>수정을 원한다면 가장 작으면서도 가치가 큰 변경은 다음과 같습니다:</p><ul><li>exec/system-event idempotency가 짧은 범위 동안 최소한 정확한 <code>(sessionKey, contextKey, text)</code> 반복에 대해서는 <code>contextKey</code>를 존중하도록 만드는 것.</li><li>또는 <code>server-node-events</code>에 <code>(sessionKey, runId, event kind)</code>로 키잉된 <code>exec.finished</code> 전용 중복 제거 로직을 추가하는 것.</li></ul><p>이렇게 하면 재전송된 <code>exec.finished</code> 중복이 세션 턴이 되기 전에 직접 차단됩니다.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/exec">Exec 도구</a></li><li><a href="/openclaw-docs-ko/concepts/session">세션 관리</a></li></ul>',44)])])}const m=o(a,[["render",n]]);export{h as __pageData,m as default};
